from typing import List

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        increments = 0
        max_bits = 0
        for num in nums:
            x = num
            bits = 0
            while x:
                increments += x & 1
                x >>= 1
                bits += 1
            if bits > max_bits:
                max_bits = bits
        # Doublings needed is max_bits - 1 if any number is non-zero
        return increments + (max_bits - 1 if max_bits > 0 else 0)
```

