class Solution:
    def strobogrammaticInRange(self, low: str, high: str) -> int:
        pairs = [('0', '0'), ('1', '1'), ('6', '9'), ('8', '8'), ('9', '6')]
        middles = ['0', '1', '8']

        def gen(n: int, total: int):
            if n == 0:
                yield ""
                return
            if n == 1:
                for c in middles:
                    yield c
                return
            for inner in gen(n - 2, total):
                for a, b in pairs:
                    if n == total and a == '0':
                        continue
                    yield a + inner + b

        len_low = len(low)
        len_high = len(high)
        count = 0

        for L in range(len_low, len_high + 1):
            for s in gen(L, L):
                if L == len_low and s < low:
                    continue
                if L == len_high and s > high:
                    continue
                count += 1
        return count
```

