class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        dp = [0] * 26  # dp[i] = longest ideal subsequence ending with char i ('a'+i)
        for ch in s:
            idx = ord(ch) - ord('a')
            l = max(0, idx - k)
            r = min(25, idx + k)
            best = 0
            for j in range(l, r + 1):
                best = max(best, dp[j])
            dp[idx] = max(dp[idx], best + 1)
        return max(dp)
```

