class Solution:
    def tilingRectangle(self, n: int, m: int) -> int:
        # Ensure n <= m to reduce branching by symmetry
        if n > m:
            n, m = m, n

        heights = [0] * m
        best = n * m  # upper bound
        seen = {}

        def dfs(count: int):
            nonlocal best

            if count >= best:
                return

            key = tuple(heights)
            prev = seen.get(key)
            if prev is not None and count >= prev:
                return
            seen[key] = count

            min_h = min(heights)
            if min_h == n:
                best = min(best, count)
                return

            i = heights.index(min_h)

            # Find contiguous block starting at i with the same minimal height
            j = i
            while j < m and heights[j] == min_h:
                j += 1

            max_k = min(n - min_h, j - i)

            # Try larger squares first to prune faster
            for k in range(max_k, 0, -1):
                # Place k x k square: increase the next k columns by k height
                for t in range(i, i + k):
                    heights[t] += k

                dfs(count + 1)

                # Backtrack
                for t in range(i, i + k):
                    heights[t] -= k

        dfs(0)
        return best
```

