class Solution:
    def tilingRectangle(self, n: int, m: int) -> int:
        if n > m:
            n, m = m, n
        if n == m:
            return 1

        heights = [0] * n  # Use the smaller side as the number of columns
        best = n * m
        seen = {}

        def dfs(count: int):
            nonlocal best

            if count >= best:
                return

            key = tuple(heights)
            prev = seen.get(key)
            if prev is not None and count >= prev:
                return
            seen[key] = count

            min_h = min(heights)
            if min_h == m:
                best = min(best, count)
                return

            i = heights.index(min_h)

            # Find the contiguous block with the same minimal height
            j = i
            while j < n and heights[j] == min_h:
                j += 1

            max_k = min(m - min_h, j - i)

            # Try larger squares first to prune faster
            for k in range(max_k, 0, -1):
                # Place k x k square: increase the next k columns by k
                for t in range(i, i + k):
                    heights[t] += k

                dfs(count + 1)

                # Backtrack
                for t in range(i, i + k):
                    heights[t] -= k

        dfs(0)
        return best
```

