from typing import List
from collections import deque

class Solution:
    def timeTaken(self, arrival: List[int], state: List[int]) -> List[int]:
        n = len(arrival)
        ans = [-1] * n
        enter_q = deque()
        exit_q = deque()

        i = 0  # next person to arrive
        t = 0  # current time
        last_used = -1  # -1: not used in previous second, 0: enter, 1: exit
        processed = 0

        while processed < n:
            while i < n and arrival[i] <= t:
                if state[i] == 0:
                    enter_q.append(i)
                else:
                    exit_q.append(i)
                i += 1

            if enter_q or exit_q:
                if enter_q and exit_q:
                    if last_used == 1:
                        idx = exit_q.popleft()
                        chosen_state = 1
                    elif last_used == 0:
                        idx = enter_q.popleft()
                        chosen_state = 0
                    else:
                        idx = exit_q.popleft()
                        chosen_state = 1
                elif exit_q:
                    idx = exit_q.popleft()
                    chosen_state = 1
                else:
                    idx = enter_q.popleft()
                    chosen_state = 0

                ans[idx] = t
                processed += 1
                last_used = chosen_state
                t += 1
            else:
                if i < n:
                    t = arrival[i]
                last_used = -1

        return ans
```

