from typing import List

class Solution:
    def minimizedMaximum(self, n: int, quantities: List[int]) -> int:
        def can_distribute(x: int) -> bool:
            # Calculate how many stores are needed if no store gets more than x items
            stores_needed = 0
            for q in quantities:
                stores_needed += (q + x - 1) // x  # ceil(q / x) without floats
                if stores_needed > n:
                    return False
            return True

        left, right = 1, max(quantities)
        while left < right:
            mid = (left + right) // 2
            if can_distribute(mid):
                right = mid
            else:
                left = mid + 1
        return left
```

