from typing import List

class Solution:
    def sumPrefixScores(self, words: List[str]) -> List[int]:
        class Node:
            __slots__ = ("children", "cnt")
            def __init__(self):
                self.children = {}
                self.cnt = 0

        root = Node()

        # Build trie and count prefixes
        for w in words:
            node = root
            for ch in w:
                if ch not in node.children:
                    node.children[ch] = Node()
                node = node.children[ch]
                node.cnt += 1

        # Compute sums of prefix scores for each word
        ans = []
        for w in words:
            node = root
            total = 0
            for ch in w:
                node = node.children[ch]
                total += node.cnt
            ans.append(total)

        return ans
```

