from typing import List

class Solution:
    def validSquare(self, p1: List[int], p2: List[int], p3: List[int], p4: List[int]) -> bool:
        def dist2(a: List[int], b: List[int]) -> int:
            return (a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2

        points = [p1, p2, p3, p4]
        dists = []

        for i in range(4):
            for j in range(i + 1, 4):
                dists.append(dist2(points[i], points[j]))

        dists.sort()

        # Four equal smallest distances (sides), two equal largest distances (diagonals)
        # Side length must be positive (no overlapping points)
        if dists[0] == 0:
            return False

        # Check 4 equal sides and 2 equal diagonals
        if not (dists[0] == dists[1] == dists[2] == dists[3]):
            return False
        if not (dists[4] == dists[5]):
            return False

        # For a square, diagonal^2 = 2 * side^2
        return dists[4] == 2 * dists[0]
```

