from typing import List
from collections import deque

class Solution:
    def minFlips(self, mat: List[List[int]]) -> int:
        m, n = len(mat), len(mat[0])

        # Convert matrix to bitmask state
        start = 0
        for i in range(m):
            for j in range(n):
                if mat[i][j]:
                    start |= 1 << (i * n + j)

        if start == 0:
            return 0

        # Precompute flip masks for each cell
        flips = []
        directions = [(0,0), (1,0), (-1,0), (0,1), (0,-1)]
        for i in range(m):
            for j in range(n):
                mask = 0
                for dx, dy in directions:
                    x, y = i + dx, j + dy
                    if 0 <= x < m and 0 <= y < n:
                        mask ^= 1 << (x * n + y)
                flips.append(mask)

        # BFS over states
        visited = {start}
        q = deque([(start, 0)])

        while q:
            state, steps = q.popleft()
            if state == 0:
                return steps
            for mask in flips:
                nxt = state ^ mask
                if nxt not in visited:
                    visited.add(nxt)
                    q.append((nxt, steps + 1))

        return -1
```

