from typing import List

class Solution:
    def reversePairs(self, nums: List[int]) -> int:
        def sort_count(arr, l, r):
            if r - l <= 1:
                return 0
            m = (l + r) // 2
            count = sort_count(arr, l, m) + sort_count(arr, m, r)

            # Count reverse pairs where i in [l, m) and j in [m, r)
            j = m
            for i in range(l, m):
                while j < r and arr[i] > 2 * arr[j]:
                    j += 1
                count += j - m

            # Merge step
            temp = []
            i, j = l, m
            while i < m and j < r:
                if arr[i] <= arr[j]:
                    temp.append(arr[i])
                    i += 1
                else:
                    temp.append(arr[j])
                    j += 1
            if i < m:
                temp.extend(arr[i:m])
            if j < r:
                temp.extend(arr[j:r])
            arr[l:r] = temp
            return count

