class Solution:
    def canConvert(self, str1: str, str2: str) -> bool:
        # If strings are already equal, no conversions needed.
        if str1 == str2:
            return True

        mapping = {}
        for a, b in zip(str1, str2):
            if a in mapping:
                if mapping[a] != b:
                    return False
            else:
                mapping[a] = b

        # If all 26 letters are used as targets and strings differ,
        # we cannot break cycles (no spare letter).
        if len(set(mapping.values())) == 26:
            return False

        return True
