class Solution:
    def buildArray(self, nums: List[int]) -> List[int]:
        n = len(nums)
        # Encode both old and new values into nums[i]:
        # new_value = nums[nums[i]]; store as nums[i] += new_value * n
        for i in range(n):
            nums[i] += (nums[nums[i]] % n) * n
        # Extract the new values by integer division
        for i in range(n):
            nums[i] //= n
        return nums
