class Solution:
    def onesMinusZeros(self, grid: List[List[int]]) -> List[List[int]]:
        m = len(grid)
        n = len(grid[0])

        row_ones = [sum(row) for row in grid]
        col_ones = [0] * n
        for i in range(m):
            for j, v in enumerate(grid[i]):
                col_ones[j] += v

        const = -(m + n)
        diff = []
        for i in range(m):
            twice_r = 2 * row_ones[i]
            row_diff = []
            for j in range(n):
                row_diff.append(twice_r + 2 * col_ones[j] + const)
            diff.append(row_diff)

        return diff
```

