class Solution:
    def reconstructMatrix(self, upper: int, lower: int, colsum: List[int]) -> List[List[int]]:
        n = len(colsum)
        # Quick feasibility check: total ones must match sum of rows
        if sum(colsum) != upper + lower:
            return []

        upper_row = [0] * n
        lower_row = [0] * n

        # First, assign columns with sum 2 (must be 1 in both rows)
        for i, c in enumerate(colsum):
            if c == 2:
                upper_row[i] = 1
                lower_row[i] = 1
                upper -= 1
                lower -= 1
                if upper < 0 or lower < 0:
                    return []

        # Then, assign columns with sum 1
        for i, c in enumerate(colsum):
            if c == 1:
                if upper > 0:
                    upper_row[i] = 1
                    upper -= 1
                else:
                    lower_row[i] = 1
                    lower -= 1
                if upper < 0 or lower < 0:
                    return []

        # All quotas must be exactly met
        if upper != 0 or lower != 0:
            return []

        return [upper_row, lower_row]
