class Solution:
    def minimumCost(self, n: int, connections: List[List[int]]) -> int:
        # If there's only one city, no cost is needed to connect
        if n == 1:
            return 0

        # Disjoint Set Union (Union-Find) with path compression and union by size
        parent = list(range(n + 1))
        size = [1] * (n + 1)

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]  # Path compression
                x = parent[x]
            return x

        def union(a: int, b: int) -> bool:
            ra, rb = find(a), find(b)
            if ra == rb:
                return False
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]
            return True

        # Sort connections by cost
        connections.sort(key=lambda x: x[2])

        total_cost = 0
        components = n

        for x, y, cost in connections:
            if union(x, y):
                total_cost += cost
                components -= 1
                if components == 1:
                    return total_cost

        return -1
```

