from typing import List

class Solution:
    def maximumLength(self, nums: List[int], k: int) -> int:
        # Coordinate compression for values
        id_map = {}
        dp = []  # dp[val_id][t] = max length ending with val_id using at most t transitions
        g = [0] * (k + 1)  # g[t] = global max length with at most t transitions

        for x in nums:
            if x not in id_map:
                id_map[x] = len(dp)
                dp.append([0] * (k + 1))
            vid = id_map[x]

            old_row = dp[vid][:]  # snapshot of dp for this value before processing x
            old_g = g[:]          # snapshot of global bests before processing x

            for t in range(k + 1):
                # Extend with same value (no new transition)
                best = old_row[t] + 1
                # Switch from any other value (use one more transition)
                if t > 0:
                    best = max(best, old_g[t - 1] + 1)
                # Keep previous best (skip this element)
                dp[vid][t] = max(old_row[t], best)

            # Update global bests
            for t in range(k + 1):
                if dp[vid][t] > g[t]:
                    g[t] = dp[vid][t]

        return max(g)
```

