from typing import List

class Solution:
    def resultGrid(self, image: List[List[int]], threshold: int) -> List[List[int]]:
        m, n = len(image), len(image[0])
        sumAcc = [[0] * n for _ in range(m)]
        cnt = [[0] * n for _ in range(m)]

        for i in range(m - 2):
            for j in range(n - 2):
                valid = True
                # Check horizontal adjacents within the 3x3
                for r in range(i, i + 3):
                    row = image[r]
                    if (abs(row[j] - row[j + 1]) > threshold or
                        abs(row[j + 1] - row[j + 2]) > threshold):
                        valid = False
                        break
                if not valid:
                    continue
                # Check vertical adjacents within the 3x3
                for c in range(j, j + 3):
                    if (abs(image[i][c] - image[i + 1][c]) > threshold or
                        abs(image[i + 1][c] - image[i + 2][c]) > threshold):
                        valid = False
                        break
                if not valid:
                    continue

                # Compute floor average for the region
                s = 0
                for r in range(i, i + 3):
                    for c in range(j, j + 3):
                        s += image[r][c]
                avg = s // 9

                # Accumulate this region's average to all its pixels
                for r in range(i, i + 3):
                    saRow = sumAcc[r]
                    cntRow = cnt[r]
                    for c in range(j, j + 3):
                        saRow[c] += avg
                        cntRow[c] += 1

        # Build result
        result = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                if cnt[i][j] > 0:
                    result[i][j] = sumAcc[i][j] // cnt[i][j]
                else:
                    result[i][j] = image[i][j]
        return result
```

