        odd_points = 0
        curr = head
        while curr and curr.next:
            if curr.val > curr.next.val:
                even_points += 1
            else:
                odd_points += 1
            curr = curr.next.next
        if even_points > odd_points:
            return "Even"
        elif odd_points > even_points:
            return "Odd"
        else:
            return "Tie"
