class Solution:
    def largestMerge(self, word1: str, word2: str) -> str:
        i, j = 0, 0
        n, m = len(word1), len(word2)
        res = []

        def greater(i, j):
            a, b = i, j
            while a < n and b < m and word1[a] == word2[b]:
                a += 1
                b += 1
            if a == n and b == m:
                return False
            if a == n:
                return False
            if b == m:
                return True
            return word1[a] > word2[b]

        while i < n and j < m:
            if word1[i] > word2[j]:
                res.append(word1[i])
                i += 1
            elif word1[i] < word2[j]:
                res.append(word2[j])
                j += 1
            else:
                if greater(i, j):
                    res.append(word1[i])
                    i += 1
                else:
                    res.append(word2[j])
                    j += 1

        if i < n:
            res.append(word1[i:])
        if j < m:
            res.append(word2[j:])
        return "".join(res)
