from typing import List

class Solution:
    def maximumCost(self, n: int, highways: List[List[int]], k: int) -> int:
        # If k edges require k+1 distinct cities; cannot exceed n
        if k > n - 1:
            return -1

        # Build adjacency list
        adj = [[] for _ in range(n)]
        for a, b, w in highways:
            adj[a].append((b, w))
            adj[b].append((a, w))

        max_mask = 1 << n
        # dp[mask][v] = max cost to end at city v, visiting exactly the set 'mask'
        dp = [[-1] * n for _ in range(max_mask)]
        for i in range(n):
            dp[1 << i][i] = 0  # starting at any city with 0 edges

        # Precompute masks by size to avoid repeated bit_count checks
        max_size = min(k + 1, n)
        masks_by_size = [[] for _ in range(max_size + 1)]
        for mask in range(1, max_mask):
            bc = mask.bit_count()
            if 1 <= bc <= max_size:
                masks_by_size[bc].append(mask)

        res = -1
        # Iterate by number of vertices in the path (s = edges + 1)
        for s in range(2, k + 1 + 1):
            for mask in masks_by_size[s]:
                temp = mask
                while temp:
                    lsb = temp & -temp
                    v = (lsb.bit_length() - 1)
                    temp ^= lsb
                    prev_mask = mask ^ (1 << v)
                    best = -1
                    # Transition from any neighbor u in prev_mask
                    for u, w in adj[v]:
                        if (prev_mask >> u) & 1:
                            prev_val = dp[prev_mask][u]
                            if prev_val != -1:
                                cost = prev_val + w
                                if cost > best:
                                    best = cost
                    dp[mask][v] = best
                    if s == k + 1 and best != -1:
                        if best > res:
                            res = best

        return res
```

