from collections import deque

class Solution:
    def minimumObstacles(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        total = m * n
        INF = 10**9
        dist = [INF] * total
        dist[0] = 0
        dq = deque([0])

        while dq:
            idx = dq.popleft()
            if idx == total - 1:
                return dist[idx]

            r, c = divmod(idx, n)
            curr = dist[idx]

            # Up
            if r > 0:
                ni = idx - n
                w = grid[r - 1][c]
                nd = curr + w
                if nd < dist[ni]:
                    dist[ni] = nd
                    if w == 0:
                        dq.appendleft(ni)
                    else:
                        dq.append(ni)

            # Down
            if r + 1 < m:
                ni = idx + n
                w = grid[r + 1][c]
                nd = curr + w
                if nd < dist[ni]:
                    dist[ni] = nd
                    if w == 0:
                        dq.appendleft(ni)
                    else:
                        dq.append(ni)

            # Left
            if c > 0:
                ni = idx - 1
                w = grid[r][c - 1]
                nd = curr + w
                if nd < dist[ni]:
                    dist[ni] = nd
                    if w == 0:
                        dq.appendleft(ni)
