                ni = idx + 1
                w = grid[r][c + 1]
                nd = curr + w
                if nd < dist[ni]:
                    dist[ni] = nd
                    if w == 0:
                        dq.appendleft(ni)
                    else:
                        dq.append(ni)

        return dist[total - 1]
