class Solution:
    def minMaxDifference(self, num: int) -> int:
        s = str(num)

        # Compute maximum by replacing the first digit (from left) that is not '9' with '9'
        max_str = s
        for ch in s:
            if ch != '9':
                max_str = s.replace(ch, '9')
                break
        max_val = int(max_str)

        # Compute minimum by replacing the first digit (from left) that is not '0' with '0'
        min_str = s
        for ch in s:
            if ch != '0':
                min_str = s.replace(ch, '0')
                break
        min_val = int(min_str)

        return max_val - min_val
