from typing import List

class Solution:
    def minScoreTriangulation(self, values: List[int]) -> int:
        n = len(values)
        # dp[i][j] = minimum score to triangulate polygon from vertex i to j (inclusive)
        dp = [[0] * n for _ in range(n)]

        # Consider chains of length >= 3 (gap >= 2)
        for gap in range(2, n):
            for i in range(n - gap):
                j = i + gap
                best = float('inf')
                for k in range(i + 1, j):
                    cost = dp[i][k] + dp[k][j] + values[i] * values[k] * values[j]
                    if cost < best:
                        best = cost
                dp[i][j] = best if best != float('inf') else 0

        return dp[0][n - 1]
```

