                pj[i + 1] = s

        NEG = -10**30

        # Helper to compute pair contribution between columns j and j+1
        def pair_cost(j: int, dj: int, dk: int) -> int:
            if dj < dk:
                return pref[j][dk] - pref[j][dj]
            elif dk < dj:
                return pref[j + 1][dj] - pref[j + 1][dk]
            else:
                return 0

        # Initialize dp for the first pair of columns (0 and 1):
        # dp[d0][d1] = Pair(0, d0, d1)
        size = n + 1
        dp = [[NEG] * size for _ in range(size)]
        for d0 in range(size):
            for d1 in range(size):
                dp[d0][d1] = pair_cost(0, d0, d1)

        # Process columns j=1..n-2
        for j in range(1, n - 1):
            next_dp = [[NEG] * size for _ in range(size)]
            pref_j = pref[j]

            for dj in range(size):
                # Build A[K] = max_{p<=K} dp[p][dj] - max(0, pref_j[p] - pref_j[dj])
                A = [NEG] * size
                run = NEG
                base_dj = pref_j[dj]
                for K in range(size):
                    p = K
                    val = dp[p][dj]
                    delta = pref_j[p] - base_dj
                    if delta > 0:
                        val -= delta
                    if val > run:
                        run = val
                    A[K] = run

                # Build Suf[p] = max_{t>=p} dp[t][dj], length n+2 so Suf[n+1]=NEG
                Suf = [NEG] * (size + 1)
                for p in range(size - 1, -1, -1):
                    v = dp[p][dj]
                    if Suf[p + 1] > v:
                        Suf[p] = Suf[p + 1]
                    else:
                        Suf[p] = v

                # For each dk, compute best previous and add pair cost
                for dk in range(size):
                    # Case d_{j-1} <= dk
                    best_prev = A[dk]
                    # Case d_{j-1} > dk
                    other = Suf[dk + 1] if dk < n else NEG
                    if other != NEG:
                        delta2 = pref_j[dk] - base_dj
                        if delta2 > 0:
                            best_prev = max(best_prev, other - delta2)
                        else:
                            best_prev = max(best_prev, other)

                    # Add pair contribution between columns j and j+1
                    pc = pair_cost(j, dj, dk)
                    total = best_prev + pc
                    next_dp[dj][dk] = total

            dp = next_dp

        # The answer is the maximum over last dp
        ans = NEG
        for row in dp:
            row_max = max(row)
            if row_max > ans:
