from typing import List

class Solution:
    def minArea(self, image: List[List[str]], x: int, y: int) -> int:
        m = len(image)
        n = len(image[0])

        def col_has_one(j: int) -> bool:
            for i in range(m):
                if image[i][j] == '1':
                    return True
            return False

        def row_has_one(i: int) -> bool:
            for j in range(n):
                if image[i][j] == '1':
                    return True
            return False

        # Find left boundary (minimum column with a '1')
        lo, hi = 0, y
        while lo < hi:
            mid = (lo + hi) // 2
            if col_has_one(mid):
                hi = mid
            else:
                lo = mid + 1
        left = lo

        # Find right boundary (maximum column with a '1')
        lo, hi = y, n - 1
        while lo < hi:
