from typing import List

class Solution:
    def minimumTime(self, time: List[int], totalTrips: int) -> int:
        # Binary search over time
        low = 1
        high = min(time) * totalTrips  # Upper bound: fastest bus doing all trips

        while low < high:
            mid = (low + high) // 2
            trips = 0
            for t in time:
                trips += mid // t
                if trips >= totalTrips:  # Early stop to avoid unnecessary work
                    break
            if trips >= totalTrips:
                high = mid
            else:
                low = mid + 1
        return low
