class Solution:
    def isItPossible(self, word1: str, word2: str) -> bool:
        # Frequency arrays for 26 lowercase letters
        cnt1 = [0] * 26
        cnt2 = [0] * 26
        base = ord('a')
        for ch in word1:
            cnt1[ord(ch) - base] += 1
        for ch in word2:
            cnt2[ord(ch) - base] += 1

        d1 = sum(1 for x in cnt1 if x > 0)
        d2 = sum(1 for x in cnt2 if x > 0)

        # Try swapping each pair of existing letters (i from word1, j from word2)
        for i in range(26):
            if cnt1[i] == 0:
                continue
            for j in range(26):
                if cnt2[j] == 0:
                    continue
                if i == j:
                    # Swapping same letter does nothing to distinct counts
                    if d1 == d2:
                        return True
                    continue
                # Compute resulting distinct counts after swapping i (from word1) with j (from word2)
                nd1 = d1
                nd2 = d2
                # Word1: remove i
                if cnt1[i] == 1:
                    nd1 -= 1
                # Word1: add j
                if cnt1[j] == 0:
                    nd1 += 1
                # Word2: remove j
                if cnt2[j] == 1:
                    nd2 -= 1
                # Word2: add i
                if cnt2[i] == 0:
                    nd2 += 1
                if nd1 == nd2:
                    return True

        return False
```

from typing import List

class Solution:
    def minimumTime(self, nums1: List[int], nums2: List[int], x: int) -> int:
        n = len(nums1)
        sumA = sum(nums1)
        sumB = sum(nums2)
        pairs = list(zip(nums1, nums2))
        pairs.sort(key=lambda p: p[1], reverse=True)

        def can(t: int) -> bool:
            dp = [-10**18] * (t + 1)
            dp[0] = 0
            for a, b in pairs:
                for j in range(t, 0, -1):
                    cand = dp[j - 1] + a + b * (t - j + 1)
                    if cand > dp[j]:
                        dp[j] = cand
            best_reduction = max(dp)
            final_sum = sumA + t * sumB - best_reduction
            return final_sum <= x

        left, right = 0, n
        ans = -1
        while left <= right:
            mid = (left + right) // 2
            if can(mid):
                ans = mid
                right = mid - 1
            else:
                left = mid + 1
        return ans

