    def maxSum(self, nums: List[int]) -> int:
        groups = {}
        for n in nums:
            max_digit = max(int(ch) for ch in str(n))
            if max_digit not in groups:
                groups[max_digit] = []
            groups[max_digit].append(n)
            groups[max_digit].sort(reverse=True)
            if len(groups[max_digit]) > 2:
