from typing import List

class Solution:
    def maxSum(self, nums: List[int]) -> int:
        def max_digit(n: int) -> int:
            m = 0
            while n:
                d = n % 10
                if d > m:
                    m = d
                    if m == 9:
                        break
                n //= 10
            return m

        tops = {}
        for n in nums:
            d = max_digit(n)
            if d not in tops:
                tops[d] = [n, None]
            else:
                a, b = tops[d]
                if a is None or n >= a:
                    tops[d] = [n, a]
                elif b is None or n > b:
                    tops[d][1] = n

        ans = -1
        for a, b in tops.values():
            if b is not None:
                s = a + b
                if s > ans:
                    ans = s
        return ans
```

