from typing import List

class Solution:
    def threeSumSmaller(self, nums: List[int], target: int) -> int:
        n = len(nums)
        if n < 3:
            return 0
        nums.sort()
        count = 0
        for i in range(n - 2):
            # If the smallest possible sum with current i is already >= target, break
            if nums[i] + nums[i + 1] + nums[i + 2] >= target:
                break
            # If the largest possible sum with current i is still < target, add all pairs
            if nums[i] + nums[n - 2] + nums[n - 1] < target:
                m = n - i - 1
                count += m * (m - 1) // 2
                continue
            l, r = i + 1, n - 1
            while l < r:
                s = nums[i] + nums[l] + nums[r]
                if s < target:
                    count += r - l
                    l += 1
                else:
                    r -= 1
        return count
```

