from typing import List

class Solution:
    def divisibleTripletCount(self, nums: List[int], d: int) -> int:
        n = len(nums)
        if n < 3:
            return 0

        # Compute residues
        r = [x % d for x in nums]

        # Initialize prefix and suffix residue counts
        prefix = {}
        prefix[r[0]] = 1

        suffix = {}
        for i in range(2, n):
            residue = r[i]
            suffix[residue] = suffix.get(residue, 0) + 1

        ans = 0
        for j in range(1, n - 1):
            rj = r[j]

            # Count contributions using the smaller of prefix or suffix maps
            if len(prefix) <= len(suffix):
                for ri, cnt_i in prefix.items():
                    target = (-(ri + rj)) % d
                    cnt_k = suffix.get(target, 0)
                    if cnt_k:
                        ans += cnt_i * cnt_k
            else:
                for rk, cnt_k in suffix.items():
                    need_ri = (-(rk + rj)) % d
                    cnt_i = prefix.get(need_ri, 0)
                    if cnt_i:
                        ans += cnt_i * cnt_k

            # Move current element from middle to prefix for next iteration
            prefix[rj] = prefix.get(rj, 0) + 1

            # Remove the next element from suffix (since next j increases)
            if j + 1 < n:
                next_res = r[j + 1]
                cnt = suffix.get(next_res, 0)
                if cnt <= 1:
                    suffix.pop(next_res, None)
                else:
                    suffix[next_res] = cnt - 1

        return ans
```

