        r = [x % d for x in nums]

        prefix = {r[0]: 1}
        suffix = {}
        for i in range(2, n):
            residue = r[i]
            suffix[residue] = suffix.get(residue, 0) + 1

        ans = 0
        for j in range(1, n - 1):
