                    if cnt_k:
                        ans += cnt_i * cnt_k
            else:
                for rk, cnt_k in suffix.items():
                    need_ri = (-(rk + rj)) % d
                    cnt_i = prefix.get(need_ri, 0)
                    if cnt_i:
