class Solution:
    def minChanges(self, n: int, k: int) -> int:
        # It's only possible if all 1-bits in k are also 1-bits in n
        if (n | k) != n:
            return -1
        # Count the 1-bits in n that need to be turned off (where k has 0)
        diff = n & ~k
        return bin(diff).count('1')
```

