from typing import List

class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        def compute_lps(p: str) -> List[int]:
            m = len(p)
            lps = [0] * m
            length = 0
            i = 1
            while i < m:
                if p[i] == p[length]:
                    length += 1
                    lps[i] = length
                    i += 1
                else:
                    if length != 0:
                        length = lps[length - 1]
                    else:
                        lps[i] = 0
                        i += 1
            return lps

        def kmp_search(text: str, pat: str) -> List[int]:
            n, m = len(text), len(pat)
            if m == 0 or m > n:
                return []
            lps = compute_lps(pat)
            res = []
            i = j = 0
            while i < n:
                if text[i] == pat[j]:
                    i += 1
                    j += 1
                    if j == m:
                        res.append(i - j)
                        j = lps[j - 1]
                else:
                    if j != 0:
                        j = lps[j - 1]
                    else:
                        i += 1
            return res

        ia = kmp_search(s, a)
        ib = kmp_search(s, b)

        res = []
        p = 0
        m = len(ib)
        for i in ia:
            while p < m and ib[p] < i - k:
                p += 1
            if p < m and ib[p] <= i + k:
                res.append(i)
        return res
```

