class Solution:
    def findLUSlength(self, a: str, b: str) -> int:
        # If strings are equal, no uncommon subsequence exists.
        if a == b:
            return -1
        # Otherwise, the longer string itself is an uncommon subsequence.
        # If lengths are equal but strings differ, that length is still the answer.
        return max(len(a), len(b))
