class Solution:
    def kthFactor(self, n: int, k: int) -> int:
        small = []
        large = []
        i = 1
        while i * i <= n:
            if n % i == 0:
                small.append(i)
                other = n // i
                if other != i:
                    large.append(other)
            i += 1

        total = len(small) + len(large)
        if k > total:
            return -1
        if k <= len(small):
            return small[k - 1]
        # Get from the reversed 'large' list
        remaining = k - len(small)
        return large[-remaining]
