from typing import List

class Solution:
    def minDayskVariants(self, points: List[List[int]], k: int) -> int:
        n = len(points)
        U = [x + y for x, y in points]
        V = [x - y for x, y in points]

        def possible(d: int) -> bool:
            # Candidates for u0 and v0 (center in rotated coordinates)
            # Include endpoints and endpoints +/- 1 to handle parity/plateau issues.
            Uc = set()
            Vc = set()
            for ui, vi in zip(U, V):
                Uc.add(ui - d)
                Uc.add(ui + d)
                Uc.add(ui - d + 1)
                Uc.add(ui + d - 1)
                Vc.add(vi - d)
                Vc.add(vi + d)
                Vc.add(vi - d + 1)
                Vc.add(vi + d - 1)

            # For each u0 candidate, filter active indices by U condition once
            for u0 in Uc:
                active = [i for i in range(n) if abs(U[i] - u0) <= d]
                if len(active) < k:
                    continue
                for v0 in Vc:
                    # Parity condition: u0 and v0 must have same parity to correspond to integer (x, y)
                    if ((u0 + v0) & 1) != 0:
                        continue
                    cnt = 0
                    for i in active:
                        if abs(V[i] - v0) <= d:
                            cnt += 1
                            if cnt >= k:
                                return True
            return False

        # Binary search on days d
        lo, hi = 0, 1
        # Ensure hi is sufficient
        while not possible(hi):
            hi *= 2

        while lo < hi:
            mid = (lo + hi) // 2
            if possible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
