class Solution:
    def lengthLongestPath(self, input: str) -> int:
        max_len = 0
        # Map depth -> cumulative length up to that depth (including slashes)
        depth_len = {0: 0}

        for line in input.split('\n'):
            # Determine depth by counting leading tabs
            name = line.lstrip('\t')
            depth = len(line) - len(name)

            if '.' in name:
                # It's a file; update max length
                max_len = max(max_len, depth_len[depth] + len(name))
            else:
                # It's a directory; store cumulative length for next depth
                # Add 1 for the '/' that will be used to join with children
                depth_len[depth + 1] = depth_len[depth] + len(name) + 1

        return max_len
```

