from typing import List
from collections import deque

class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        RED, BLUE = 0, 1

        red_adj = [[] for _ in range(n)]
        blue_adj = [[] for _ in range(n)]
        for u, v in redEdges:
            red_adj[u].append(v)
        for u, v in blueEdges:
            blue_adj[u].append(v)

        ans = [-1] * n
        visited = [[False, False] for _ in range(n)]  # visited[node][color]
        q = deque()

        # Start from node 0 with both colors as last used, distance 0
        q.append((0, RED, 0))
        q.append((0, BLUE, 0))
        visited[0][RED] = True
        visited[0][BLUE] = True

        while q:
            node, last_color, dist = q.popleft()
            if ans[node] == -1 or dist < ans[node]:
                ans[node] = dist

            if last_color == RED:
                # Next must be BLUE
                for nei in blue_adj[node]:
                    if not visited[nei][BLUE]:
                        visited[nei][BLUE] = True
                        q.append((nei, BLUE, dist + 1))
            else:
                # Next must be RED
                for nei in red_adj[node]:
                    if not visited[nei][RED]:
                        visited[nei][RED] = True
                        q.append((nei, RED, dist + 1))

        return ans
```

