class Solution:
    def idealArrays(self, n: int, maxValue: int) -> int:
        MOD = 10**9 + 7

        # Sieve to get primes up to maxValue
        def sieve(limit):
            is_prime = [True] * (limit + 1)
            is_prime[0] = is_prime[1] = False
            primes = []
            for i in range(2, limit + 1):
                if is_prime[i]:
                    primes.append(i)
                    step = i
                    start = i * i
                    if start > limit:
                        continue
                    for j in range(start, limit + 1, step):
                        is_prime[j] = False
            return primes

        primes = sieve(maxValue)

        # Factorization using the list of primes
        def factorize(x):
            exps = []
            for p in primes:
                if p * p > x:
                    break
                if x % p == 0:
                    e = 0
                    while x % p == 0:
                        x //= p
                        e += 1
                    exps.append(e)
            if x > 1:
                exps.append(1)
            return exps

        # Maximum exponent for any prime factor <= maxValue is for prime 2
        emax = 0
        t = 1
        while t * 2 <= maxValue:
            t *= 2
            emax += 1

        # Precompute factorials and inverse factorials up to n-1 + emax
        max_comb_n = (n - 1) + emax
        if max_comb_n < 0:
            max_comb_n = 0
        fac = [1] * (max_comb_n + 1)
        for i in range(1, max_comb_n + 1):
            fac[i] = fac[i - 1] * i % MOD

        invfac = [1] * (max_comb_n + 1)
        invfac[max_comb_n] = pow(fac[max_comb_n], MOD - 2, MOD)
        for i in range(max_comb_n - 1, -1, -1):
            invfac[i] = invfac[i + 1] * (i + 1) % MOD

        def comb(a, b):
            if b < 0 or b > a:
                return 0
            return fac[a] * invfac[b] % MOD * invfac[a - b] % MOD

        # Sum over all values v from 1 to maxValue
        ans = 0
        for v in range(1, maxValue + 1):
            total = 1
            exps = factorize(v)
            for e in exps:
                total = (total * comb((n - 1) + e, e)) % MOD
            ans += total
            if ans >= MOD:
                ans -= MOD

        return ans % MOD
```

