from typing import List
from functools import lru_cache

class Solution:
    def ways(self, pizza: List[str], k: int) -> int:
        MOD = 10**9 + 7
        R, C = len(pizza), len(pizza[0])

        # Suffix sum of apples: pre[i][j] = number of apples in submatrix (i..R-1, j..C-1)
        pre = [[0] * (C + 1) for _ in range(R + 1)]
        for i in range(R - 1, -1, -1):
            for j in range(C - 1, -1, -1):
                pre[i][j] = (1 if pizza[i][j] == 'A' else 0) + pre[i + 1][j] + pre[i][j + 1] - pre[i + 1][j + 1]

        @lru_cache(maxsize=None)
        def dfs(i: int, j: int, pieces: int) -> int:
            # If no apples in current submatrix, invalid
            if pre[i][j] == 0:
                return 0
            # If only one piece left, and it has apples, it's valid
            if pieces == 1:
                return 1

            ans = 0
            # Try horizontal cuts: cut between row r-1 and r; give top part away
            for r in range(i + 1, R):
                # Top part has apples if pre[i][j] - pre[r][j] > 0
                if pre[i][j] - pre[r][j] > 0:
                    ans += dfs(r, j, pieces - 1)
                    if ans >= MOD:
                        ans -= MOD
            # Try vertical cuts: cut between col c-1 and c; give left part away
            for c in range(j + 1, C):
                # Left part has apples if pre[i][j] - pre[i][c] > 0
                if pre[i][j] - pre[i][c] > 0:
                    ans += dfs(i, c, pieces - 1)
                    if ans >= MOD:
                        ans -= MOD
            return ans % MOD

        return dfs(0, 0, k) % MOD
```

