from typing import List
from collections import defaultdict

class Solution:
    def checkWays(self, pairs: List[List[int]]) -> int:
        # Build adjacency sets
        g = defaultdict(set)
        for x, y in pairs:
            g[x].add(y)
            g[y].add(x)
        nodes = list(g.keys())
        n = len(nodes)
        # Find root: node connected to all others
        root = -1
        for u in nodes:
            if len(g[u]) == n - 1:
                root = u
                break
        if root == -1:
            return 0

        multiple = False

        # For each node, determine its parent
        for u in nodes:
            if u == root:
                continue
            parent = -1
            parent_deg = float('inf')
            deg_u = len(g[u])
            # Parent must be a neighbor with minimal degree >= deg_u
            for v in g[u]:
                deg_v = len(g[v])
                if deg_v >= deg_u and deg_v < parent_deg:
                    parent = v
                    parent_deg = deg_v
            if parent == -1:
                return 0
            # Check that all neighbors of u (except parent) are also neighbors of parent
            for v in g[u]:
                if v == parent:
                    continue
                if v not in g[parent]:
                    return 0
            # If parent and u have same degree, there are multiple possible trees
            if parent_deg == deg_u:
                multiple = True

        return 2 if multiple else 1
```

