from typing import List

class Solution:
    def kWeakestRows(self, mat: List[List[int]], k: int) -> List[int]:
        def count_soldiers(row: List[int]) -> int:
            # Binary search to find the first 0 (since 1s come before 0s)
            left, right = 0, len(row)
            while left < right:
                mid = (left + right) // 2
                if row[mid] == 1:
                    left = mid + 1
                else:
                    right = mid
            return left  # number of 1s

        strengths = []
        for i, row in enumerate(mat):
            cnt = count_soldiers(row)
            strengths.append((cnt, i))

        strengths.sort()
        return [idx for _, idx in strengths[:k]]
