class Solution:
    def countMatchingSubarrays(self, nums: List[int], pattern: List[int]) -> int:
        n = len(nums)
        m = len(pattern)

        # Build LPS (Longest Prefix Suffix) array for the pattern
        lps = [0] * m
        length = 0
        i = 1
        while i < m:
            if pattern[i] == pattern[length]:
                length += 1
                lps[i] = length
                i += 1
            else:
                if length != 0:
                    length = lps[length - 1]
                else:
                    lps[i] = 0
                    i += 1

        # KMP search over the sign comparisons generated on-the-fly
        count = 0
        j = 0  # index for pattern
        for k in range(n - 1):
            # Compute comparison sign between consecutive elements
            if nums[k + 1] > nums[k]:
                s = 1
            elif nums[k + 1] == nums[k]:
                s = 0
            else:
                s = -1

            while j > 0 and s != pattern[j]:
                j = lps[j - 1]
            if s == pattern[j]:
                j += 1
                if j == m:
                    count += 1
                    j = lps[j - 1]

        return count
