class Solution:
    def isMatch(self, s: str, p: str) -> bool:
        i, j = 0, 0
        star_j = -1  # last position of '*' in p
        star_i = -1  # position in s corresponding to star_j

        while i < len(s):
            if j < len(p) and (p[j] == s[i] or p[j] == '?'):
                # Direct match or single-char wildcard
                i += 1
                j += 1
            elif j < len(p) and p[j] == '*':
                # Record position of '*' and corresponding index in s
                star_j = j
                star_i = i
                j += 1
            elif star_j != -1:
                # Backtrack: treat '*' as matching one more character in s
                j = star_j + 1
                star_i += 1
                i = star_i
            else:
                # No match and no previous '*'
                return False

        # Ensure the rest of p consists only of '*' characters
        while j < len(p) and p[j] == '*':
            j += 1

        return j == len(p)
```

