class Solution:
    def makeIntegerBeautiful(self, n: int, target: int) -> int:
        def digit_sum(x: int) -> int:
            return sum(int(c) for c in str(x))

        if digit_sum(n) <= target:
            return 0

        add = 0
        p = 1
        while digit_sum(n) > target:
            # Increment n to make the current digit (at place p) become 0
            increment_digit = (10 - (n // p) % 10) % 10
            increment = increment_digit * p
            n += increment
            add += increment
            p *= 10
        return add
```

