from typing import List

class Solution:
    def uniquePathsIII(self, grid: List[List[int]]) -> int:
        m = len(grid)
        n = len(grid[0])

        # Count total non-obstacle cells and find start
        total = 0
        sr = sc = -1
        for i in range(m):
            for j in range(n):
                if grid[i][j] != -1:
                    total += 1
                if grid[i][j] == 1:
                    sr, sc = i, j

        dirs = [(1,0), (-1,0), (0,1), (0,-1)]

        def dfs(x: int, y: int, remain: int) -> int:
            # If we reach the end, check if we visited all cells
            if grid[x][y] == 2:
                return 1 if remain == 1 else 0

            # Mark current cell as visited
            temp = grid[x][y]
            grid[x][y] = -1
            paths = 0

            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] != -1:
                    paths += dfs(nx, ny, remain - 1)

            # Restore current cell
            grid[x][y] = temp
            return paths

        return dfs(sr, sc, total)
```

