class Solution:
    def calculate(self, s: str) -> int:
        def trunc_div(a: int, b: int) -> int:
            # Division truncated toward zero
            q = abs(a) // abs(b)
            return q if a * b >= 0 else -q

        stack = []
        num = 0
        sign = '+'
        n = len(s)

        for i, c in enumerate(s):
            if c.isdigit():
                num = num * 10 + (ord(c) - ord('0'))

            if c in '+-*/' or i == n - 1:
                if sign == '+':
                    stack.append(num)
                elif sign == '-':
                    stack.append(-num)
                elif sign == '*':
                    stack[-1] = stack[-1] * num
                elif sign == '/':
                    stack[-1] = trunc_div(stack[-1], num)
                num = 0
                if c in '+-*/':
                    sign = c

        return sum(stack)
```

