class Solution:
    def isIsomorphic(self, s: str, t: str) -> bool:
        if len(s) != len(t):
            return False

        map_s_to_t = {}
        map_t_to_s = {}

        for cs, ct in zip(s, t):
            if cs in map_s_to_t:
                if map_s_to_t[cs] != ct:
                    return False
            else:
                if ct in map_t_to_s and map_t_to_s[ct] != cs:
                    return False
                map_s_to_t[cs] = ct
                map_t_to_s[ct] = cs

        return True
