from typing import List

class Solution:
    def lengthOfLongestSubsequence(self, nums: List[int], target: int) -> int:
        # dp[s] = maximum length of a subsequence that sums to s; -inf if impossible
        NEG_INF = -10**9
        dp = [NEG_INF] * (target + 1)
        dp[0] = 0

        for x in nums:
            # Traverse in reverse to avoid reusing the same element multiple times
            for s in range(target, x - 1, -1):
                if dp[s - x] != NEG_INF:
                    dp[s] = max(dp[s], dp[s - x] + 1)

        return dp[target] if dp[target] != NEG_INF else -1
```

