from typing import Optional

# Definition for a category handler.
# class CategoryHandler:
#     def haveSameCategory(self, a: int, b: int) -> bool:
#         pass
class Solution:
    def numberOfCategories(self, n: int, categoryHandler: Optional['CategoryHandler']) -> int:
        if n <= 0:
            return 0
        if categoryHandler is None:
            # If no handler is provided, we cannot group; assume all are distinct
            return n

        representatives = []
        for i in range(n):
            found = False
            for rep in representatives:
                if categoryHandler.haveSameCategory(i, rep):
                    found = True
                    break
            if not found:
                representatives.append(i)
        return len(representatives)
