from typing import List

class Solution:
    def smallestMissingValueSubtree(self, parents: List[int], nums: List[int]) -> List[int]:
        n = len(nums)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parents[i]].append(i)

        try:
            pos1 = nums.index(1)
        except ValueError:
            return [1] * n

        ans = [1] * n
        max_val = max(nums)
        seen = [False] * (max_val + 2)
        visited_node = [False] * n

        def add_subtree(u: int):
            stack = [u]
            while stack:
                v = stack.pop()
                if visited_node[v]:
                    continue
                visited_node[v] = True
                val = nums[v]
                if val <= max_val + 1:
                    seen[val] = True
                for w in children[v]:
                    if not visited_node[w]:
                        stack.append(w)

        mex = 1
        u = pos1
        while u != -1:
            add_subtree(u)
            while mex <= max_val + 1 and seen[mex]:
                mex += 1
            ans[u] = mex
            u = parents[u]

        return ans
