from typing import List
from collections import deque

class Solution:
    def shortestPath(self, grid: List[List[int]], k: int) -> int:
        m, n = len(grid), len(grid[0])
        if m == 1 and n == 1:
            return 0
        # With enough eliminations, we can go straight in Manhattan distance
        if k >= m + n - 2:
            return m + n - 2

        # visited[r][c] stores the maximum remaining eliminations we have when reaching (r, c)
        visited = [[-1] * n for _ in range(m)]
        visited[0][0] = k

        q = deque()
        q.append((0, 0, 0, k))  # r, c, steps, remaining eliminations

        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

        while q:
            r, c, steps, rem = q.popleft()

            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    cost = grid[nr][nc]
                    new_rem = rem - cost
                    if new_rem < 0:
                        continue
                    if nr == m - 1 and nc == n - 1:
                        return steps + 1
                    if visited[nr][nc] < new_rem:
                        visited[nr][nc] = new_rem
                        q.append((nr, nc, steps + 1, new_rem))

        return -1
```

