class Solution:
    def canMouseWin(self, grid: List[str], catJump: int, mouseJump: int) -> bool:
        rows, cols = len(grid), len(grid[0])
        dirs = [(-1,0), (1,0), (0,-1), (0,1)]

        # Collect valid cells and positions of M, C, F
        pos_to_idx = {}
        idx_to_pos = []
        mouse_start = cat_start = food_pos = -1

        for r in range(rows):
            for c in range(cols):
                if grid[r][c] != '#':
                    idx = len(idx_to_pos)
                    pos_to_idx[(r, c)] = idx
                    idx_to_pos.append((r, c))
                    if grid[r][c] == 'M':
                        mouse_start = idx
                    elif grid[r][c] == 'C':
                        cat_start = idx
                    elif grid[r][c] == 'F':
                        food_pos = idx

        n = len(idx_to_pos)

        # Precompute moves for mouse and cat, including staying in place
        def compute_moves(jump: int):
            moves = [[] for _ in range(n)]
            for i in range(n):
                r, c = idx_to_pos[i]
                # Staying in place is allowed
                moves[i].append(i)
                for dr, dc in dirs:
                    nr, nc = r, c
                    for step in range(1, jump + 1):
                        nr += dr
                        nc += dc
                        if not (0 <= nr < rows and 0 <= nc < cols):
                            break
                        if grid[nr][nc] == '#':
                            break
                        moves[i].append(pos_to_idx[(nr, nc)])
            return moves

        mouse_moves = compute_moves(mouseJump)
        cat_moves = compute_moves(catJump)

        # Precompute reverse moves (parents)
        mouse_parents = [[] for _ in range(n)]
        cat_parents = [[] for _ in range(n)]
        for src in range(n):
            for dst in mouse_moves[src]:
                mouse_parents[dst].append(src)
            for dst in cat_moves[src]:
                cat_parents[dst].append(src)

        MOUSE_WIN, CAT_WIN = 1, 2

        # color[m][c][t] where t=0 mouse's turn, t=1 cat's turn
        color = [[[0, 0] for _ in range(n)] for __ in range(n)]
        degree = [[[0, 0] for _ in range(n)] for __ in range(n)]

        for m in range(n):
            for c in range(n):
                degree[m][c][0] = len(mouse_moves[m])
                degree[m][c][1] = len(cat_moves[c])

        # Initialize queue with terminal states
        q = deque()
        for m in range(n):
            for c in range(n):
                if m == food_pos:
                    if color[m][c][0] == 0:
                        color[m][c][0] = MOUSE_WIN
                        q.append((m, c, 0))
                    if color[m][c][1] == 0:
                        color[m][c][1] = MOUSE_WIN
                        q.append((m, c, 1))
                elif c == food_pos or c == m:
                    if color[m][c][0] == 0:
                        color[m][c][0] = CAT_WIN
                        q.append((m, c, 0))
                    if color[m][c][1] == 0:
                        color[m][c][1] = CAT_WIN
                        q.append((m, c, 1))

        # Retrograde analysis via BFS
        while q:
            m, c, t = q.popleft()
            res = color[m][c][t]
            prev_t = 1 - t
            if t == 0:
                # Current is mouse's turn, previous was cat's turn
                # Parents: (m, pc, 1) where pc can move to c
                for pc in cat_parents[c]:
                    pm, pt = m, 1
                    if color[pm][pc][pt] != 0:
                        continue
                    # If the player to move (cat) can move to a CAT_WIN, or to a MOUSE_WIN accordingly
                    if res == CAT_WIN and pt == 1:
                        color[pm][pc][pt] = CAT_WIN
                        q.append((pm, pc, pt))
                    else:
                        degree[pm][pc][pt] -= 1
                        if degree[pm][pc][pt] == 0:
                            color[pm][pc][pt] = res
                            q.append((pm, pc, pt))
            else:
                # Current is cat's turn, previous was mouse's turn
                # Parents: (pm, c, 0) where pm can move to m
                for pm in mouse_parents[m]:
                    pc, pt = c, 0
                    if color[pm][pc][pt] != 0:
                        continue
                    if res == MOUSE_WIN and pt == 0:
                        color[pm][pc][pt] = MOUSE_WIN
                        q.append((pm, pc, pt))
                    else:
                        degree[pm][pc][pt] -= 1
                        if degree[pm][pc][pt] == 0:
                            color[pm][pc][pt] = res
                            q.append((pm, pc, pt))

        # If unresolved, by problem rule it's a cat win (mouse cannot ensure win within limit)
        return color[mouse_start][cat_start][0] == MOUSE_WIN
