from typing import List

class Solution:
    def containsNearbyAlmostDuplicate(self, nums: List[int], indexDiff: int, valueDiff: int) -> bool:
        if valueDiff < 0:
            return False

        w = valueDiff + 1  # bucket width
        buckets = {}  # bucket_id -> value

        for i, x in enumerate(nums):
            b = x // w  # Python's // is floor division, works for negatives too

            # Check current bucket
            if b in buckets:
                return True
            # Check neighbors
            if (b - 1 in buckets) and abs(x - buckets[b - 1]) <= valueDiff:
                return True
            if (b + 1 in buckets) and abs(x - buckets[b + 1]) <= valueDiff:
                return True

            buckets[b] = x

            # Maintain sliding window of size indexDiff
            if i >= indexDiff:
                old = nums[i - indexDiff]
                old_b = old // w
                if old_b in buckets:
                    del buckets[old_b]

        return False
```

