from typing import List

class Solution:
    def numSubmat(self, mat: List[List[int]]) -> int:
        m = len(mat)
        n = len(mat[0]) if m else 0
        heights = [0] * n
        res = 0

        for i in range(m):
            # Build histogram of consecutive ones up to current row
            for j in range(n):
                if mat[i][j] == 1:
                    heights[j] += 1
                else:
                    heights[j] = 0

            # Count submatrices with bottom row at i
            for j in range(n):
                if heights[j] == 0:
                    continue
                min_h = heights[j]
                res += min_h
                k = j - 1
                while k >= 0 and heights[k] > 0:
                    min_h = min(min_h, heights[k])
                    res += min_h
                    k -= 1

        return res
