from typing import List

class Solution:
    def majorityElement(self, nums: List[int]) -> List[int]:
        n = len(nums)
        if n == 0:
            return []

        # Boyer-Moore Voting Algorithm for n/3
        cand1 = cand2 = None
        count1 = count2 = 0

        for x in nums:
            if cand1 == x:
                count1 += 1
            elif cand2 == x:
                count2 += 1
            elif count1 == 0:
                cand1 = x
                count1 = 1
            elif count2 == 0:
                cand2 = x
                count2 = 1
            else:
                count1 -= 1
                count2 -= 1

        # Verify the candidates
        count1 = count2 = 0
        for x in nums:
            if x == cand1:
                count1 += 1
            elif x == cand2:
                count2 += 1

        res = []
        if count1 > n // 3:
            res.append(cand1)
        if cand2 is not None and cand2 != cand1 and count2 > n // 3:
            res.append(cand2)

        return res
```

