from typing import List

class Solution:
    def groupStrings(self, words: List[str]) -> List[int]:
        # Build frequency map of masks
        freq = {}
        for w in words:
            m = 0
            for ch in w:
                m |= 1 << (ord(ch) - 97)
            freq[m] = freq.get(m, 0) + 1

        masks = list(freq.keys())
        n = len(masks)
        idx = {m: i for i, m in enumerate(masks)}

        parent = list(range(n))
        size = [freq[m] for m in masks]

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a: int, b: int):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]

        FULL = (1 << 26) - 1
        idx_get = idx.get

        for i, m in enumerate(masks):
            # Get set bit positions
            ones = []
            x = m
            while x:
                lsb = x & -x
                pos = lsb.bit_length() - 1
                ones.append(pos)
                x -= lsb

            # Union with deletion neighbors (remove one bit)
            for b in ones:
                dm = m ^ (1 << b)
                j = idx_get(dm)
                if j is not None:
                    union(i, j)

            # Substitution neighbors: remove one set bit, add one zero bit
            z = (~m) & FULL
            if ones and z:
                zeros = []
                y = z
                while y:
                    lsb = y & -y
                    pos = lsb.bit_length() - 1
                    zeros.append(pos)
                    y -= lsb
                for b in ones:
                    dm = m ^ (1 << b)
                    for jbit in zeros:
                        sm = dm | (1 << jbit)
                        j = idx_get(sm)
                        if j is not None:
                            union(i, j)

        # Count groups and largest group size
        seen = set()
        groups = 0
        largest = 0
        for i in range(n):
            r = find(i)
            if r not in seen:
                seen.add(r)
                groups += 1
                if size[r] > largest:
                    largest = size[r]

        return [groups, largest]
```

