from typing import List

class Solution:
    def isRectangleCover(self, rectangles: List[List[int]]) -> bool:
        if not rectangles:
            return False

        min_x = min(rect[0] for rect in rectangles)
        min_y = min(rect[1] for rect in rectangles)
        max_x = max(rect[2] for rect in rectangles)
        max_y = max(rect[3] for rect in rectangles)

        total_area = 0
        corners = set()

        for x1, y1, x2, y2 in rectangles:
            # Area sum
            area = (x2 - x1) * (y2 - y1)
            total_area += area

            # Toggle corners
            for corner in [(x1, y1), (x1, y2), (x2, y1), (x2, y2)]:
                if corner in corners:
                    corners.remove(corner)
                else:
                    corners.add(corner)

        # The set of corners must be exactly the four outer corners
        expected_corners = {(min_x, min_y), (min_x, max_y), (max_x, min_y), (max_x, max_y)}
        if corners != expected_corners:
            return False

        # The area must match the bounding rectangle's area
        bounding_area = (max_x - min_x) * (max_y - min_y)
        return total_area == bounding_area
```

