from typing import List

class Solution:
    def maxIceCream(self, costs: List[int], coins: int) -> int:
        if not costs or coins <= 0:
            return 0

        max_cost = max(costs)
        freq = [0] * (max_cost + 1)
        for c in costs:
            freq[c] += 1

        count = 0
        for price in range(1, max_cost + 1):
            if freq[price] == 0:
                continue
            if coins < price:
                break
            # Number we can buy at this price
            buy = min(freq[price], coins // price)
            count += buy
            coins -= buy * price
            if coins == 0:
                break

        return count
```

