from typing import List

class Solution:
    def minOperations(self, nums: List[int], target: int) -> int:
        total_sum = sum(nums)
        if total_sum < target:
            return -1

        MAX_BIT = 31  # handle bits 0..30
        cnt = [0] * MAX_BIT
        for x in nums:
            b = x.bit_length() - 1
            cnt[b] += 1

        ops = 0
        carry = 0  # number of 2^i units available at current bit (after processing lower bits)
        for i in range(MAX_BIT):
            carry += cnt[i]
            if (target >> i) & 1:
                if carry > 0:
                    carry -= 1
                else:
                    j = i + 1
                    while j < MAX_BIT and cnt[j] == 0:
                        j += 1
                    if j == MAX_BIT:
                        return -1
                    while j > i:
                        cnt[j] -= 1
                        cnt[j - 1] += 2
                        ops += 1
                        j -= 1
                    carry += 2
                    carry -= 1
            carry //= 2

        return ops
```

