from typing import List

class Solution:
    def numberOfPaths(self, n: int, corridors: List[List[int]]) -> int:
        # Convert to 0-based indexing
        edges = [(u - 1, v - 1) for u, v in corridors]

        # Compute degrees
        deg = [0] * n
        for u, v in edges:
            deg[u] += 1
            deg[v] += 1

        # Build forward adjacency based on degree ordering
        # Edge u-v is directed from u to v if:
        # deg[u] < deg[v] or (deg[u] == deg[v] and u < v)
        F = [[] for _ in range(n)]
        for u, v in edges:
            if deg[u] < deg[v] or (deg[u] == deg[v] and u < v):
                F[u].append(v)
            else:
                F[v].append(u)

        # Count triangles: for each u, mark all forward neighbors,
        # then for each v in F[u], count common neighbors by checking F[v]
        count = 0
        marked = [False] * n
        for u in range(n):
            if not F[u]:
                continue
            # Mark forward neighbors of u
            for w in F[u]:
                marked[w] = True
            # For each v reachable from u, check how many of its forward neighbors are also in F[u]
            for v in F[u]:
                for w in F[v]:
                    if marked[w]:
                        count += 1
            # Unmark
            for w in F[u]:
                marked[w] = False

        return count
```

