from typing import List

class Solution:
    def minimumOperations(self, nums: List[int], target: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0  # Not needed per constraints, but safe.

        prev = target[0] - nums[0]
        ans = abs(prev)

        for i in range(1, n):
            cur = target[i] - nums[i]
            if prev >= 0 and cur >= 0:
                if cur > prev:
                    ans += cur - prev
            elif prev <= 0 and cur <= 0:
                if cur < prev:
                    ans += prev - cur
            else:
                ans += abs(cur)
            prev = cur

        return ans
```

