from typing import List

class Solution:
    def findLengthOfShortestSubarray(self, arr: List[int]) -> int:
        n = len(arr)
        if n <= 1:
            return 0

        # Find the longest non-decreasing prefix
        l = 0
        while l + 1 < n and arr[l] <= arr[l + 1]:
            l += 1

        # If the whole array is non-decreasing
        if l == n - 1:
            return 0

        # Find the longest non-decreasing suffix
        r = n - 1
        while r - 1 >= 0 and arr[r - 1] <= arr[r]:
            r -= 1

        # Remove prefix or suffix entirely
        ans = min(n - (l + 1), r)

        # Try to bridge the prefix and suffix
        i, j = 0, r
        while i <= l and j < n:
            if arr[i] <= arr[j]:
                ans = min(ans, j - i - 1)
                i += 1
            else:
                j += 1

        return ans
```

