from typing import List

class Solution:
    def findReplaceString(self, s: str, indices: List[int], sources: List[str], targets: List[str]) -> str:
        # Map valid replacement start index to (source, target)
        valid = {}
        for idx, src, tgt in zip(indices, sources, targets):
            if s.startswith(src, idx):
                valid[idx] = (src, tgt)

        res = []
        i = 0
        while i < len(s):
            if i in valid:
                src, tgt = valid[i]
                res.append(tgt)
                i += len(src)
            else:
                res.append(s[i])
                i += 1
        return ''.join(res)
```

