            if a < plants[i]:
                refills += 1
                a = capacityA
            a -= plants[i]
            i += 1

            if b < plants[j]:
                refills += 1
                b = capacityB
            b -= plants[j]
            j -= 1

        if i == j:
            if max(a, b) < plants[i]:
                refills += 1

        return refills
```

