class Solution:
    def differByOne(self, dict: List[str]) -> bool:
        seen_patterns = set()
        for word in dict:
            m = len(word)
            for i in range(m):
                pattern = word[:i] + '*' + word[i+1:]
                if pattern in seen_patterns:
                    return True
                seen_patterns.add(pattern)
        return False
