class Solution:
    def removeInterval(self, intervals: List[List[int]], toBeRemoved: List[int]) -> List[List[int]]:
        r0, r1 = toBeRemoved
        res = []
        for a, b in intervals:
            # No overlap
            if b <= r0 or a >= r1:
                res.append([a, b])
                continue
            # Overlap exists, keep left part if any
            if a < r0:
                res.append([a, r0])
            # Keep right part if any
            if b > r1:
                res.append([r1, b])
        return res
