class Solution:
    def maximumLength(self, s: str) -> int:
        # Keep the three longest run lengths for each character
        top3 = [[0, 0, 0] for _ in range(26)]

        n = len(s)
        i = 0
        while i < n:
            ch = s[i]
            j = i
            while j < n and s[j] == ch:
                j += 1
            L = j - i
            idx = ord(ch) - 97
            a = top3[idx]
            # Insert L into the top-3 list (descending order)
            if L > a[0]:
                a[2] = a[1]
                a[1] = a[0]
                a[0] = L
            elif L > a[1]:
                a[2] = a[1]
                a[1] = L
            elif L > a[2]:
                a[2] = L
            i = j

        def enough(a, k):
            # Sum contributions from top three runs for length k
            ssum = 0
            for L in a:
                if L >= k:
                    ssum += L - k + 1
                    if ssum >= 3:
                        return True
            return False

        ans = 0
        for a in top3:
            if a[0] == 0:
                continue
            lo, hi = 1, a[0]
            best = 0
            while lo <= hi:
                mid = (lo + hi) // 2
                if enough(a, mid):
                    best = mid
                    lo = mid + 1
                else:
                    hi = mid - 1
            if best > ans:
                ans = best

        return ans if ans > 0 else -1
```

