from typing import List

class Solution:
    def countFairPairs(self, nums: List[int], lower: int, upper: int) -> int:
        nums.sort()

        def count_leq(target: int) -> int:
            count = 0
            i, j = 0, len(nums) - 1
            while i < j:
                if nums[i] + nums[j] <= target:
                    count += j - i
                    i += 1
                else:
                    j -= 1
            return count

        return count_leq(upper) - count_leq(lower - 1)
```

