from typing import List
import sys

class Solution:
    def maximumSubtreeSize(self, edges: List[List[int]], colors: List[int]) -> int:
        n = len(colors)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        sys.setrecursionlimit(10**6)
        max_size = 0

        def dfs(u: int, parent: int):
            nonlocal max_size
            mono = True
            size = 1
            for w in adj[u]:
                if w == parent:
                    continue
                child_mono, child_size = dfs(w, u)
                size += child_size
                if not child_mono or colors[w] != colors[u]:
                    mono = False
            if mono:
                if size > max_size:
                    max_size = size
            return mono, size

        dfs(0, -1)
        return max_size
```

