class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        # Ensure nums1 is the smaller array to keep binary search bounds minimal
        if len(nums1) > len(nums2):
            nums1, nums2 = nums2, nums1

        m, n = len(nums1), len(nums2)
        total = m + n
        half = (total + 1) // 2  # number of elements in the left partition

        left, right = 0, m
        INF = float('inf')

        while left <= right:
            i = (left + right) // 2           # partition in nums1
            j = half - i                      # partition in nums2

            left1 = -INF if i == 0 else nums1[i - 1]
            right1 = INF if i == m else nums1[i]
            left2 = -INF if j == 0 else nums2[j - 1]
            right2 = INF if j == n else nums2[j]

            if left1 <= right2 and left2 <= right1:
                if total % 2 == 0:
                    return (max(left1, left2) + min(right1, right2)) / 2.0
                else:
                    return float(max(left1, left2))
            elif left1 > right2:
                right = i - 1
            else:
                left = i + 1

        # Control should never reach here if inputs are valid per constraints
        return 0.0
```

